fun solve(nums: Array<Long>, k: Long): Long {
    val modCounts = mutableMapOf<Long, Int>()
    modCounts[0L] = 1
    var prefixMod = 0L
    var totalSum = 0L

    for (num in nums) {
        totalSum += num
        prefixMod = (prefixMod + num) % k
        modCounts[prefixMod] = modCounts.getOrDefault(prefixMod, 0) + 1
    }

    var minSum = totalSum
    for ((mod, count) in modCounts) {
        if (count > 0) {
            minSum = minOf(minSum, totalSum - (count * k))
        }
    }

    return minSum
}
